+fn frompyfunc_display_name(callable: &Bound<'_, PyAny>) -> String {
+    let base_name = callable
+        .getattr("__name__")
+        .and_then(|name| name.extract::<String>())
+        .unwrap_or_else(|_| "pyfunc".to_string());
+    format!("{base_name} (vectorized)")
